    const processarDadosPorData = (tecnicoNome, tipoTecnico) => {
        const dadosPorData = {};

        if (!dadosPlanilha) return [];

        for (const item of dadosPlanilha) {
            if (item.isTecnico) continue;
            if (item.tecnico === tecnicoNome) {
                const dataItem = extrairDataDoItem(item);
                if (!dataItem) continue;

                if (!dadosPorData[dataItem]) {
                    dadosPorData[dataItem] = {
                        data: dataItem,
                        dataFormatada: Utils.formatarData(dataItem),
                        diaSemana: getDiaSemana(dataItem),
                        produtividade: 0,
                        execucao: 0,
                        planejamento: 0,
                        remarcacao: 0,
                        cancelamento: 0,
                        tratativasCS: 0,
                        infraestrutura: 0,
                        resolucaoN2: 0,
                        totalProtocolos: 0,
                    };
                }

                const linha = item.linha;
                if (!linha) continue;

                const idxServico = 6;
                const idxFeito = 12;
                const servicoOriginal = linha[idxServico] ? linha[idxServico].toString().trim() : "";
                const feito = linha[idxFeito] ? linha[idxFeito].toString().trim() : "";
                const feitoNormalizado = Utils.normalizarTexto(feito);

                if (feitoNormalizado === "NENHUM" || feito === "0" || feito === "-" || feito === "") continue;

                dadosPorData[dataItem].planejamento++;

                if (feitoNormalizado.includes("CANCEL")) {
                    dadosPorData[dataItem].cancelamento++;
                } else if (feitoNormalizado === "RV" || feitoNormalizado === "RC") {
                    dadosPorData[dataItem].remarcacao++;
                } else {
                    const linhaCompleta = Utils.normalizarTexto(servicoOriginal + " " + feito);
                    if (linhaCompleta.includes("TRATAT")) {
                        dadosPorData[dataItem].tratativasCS++;
                    } else if (linhaCompleta.includes("INFRA")) {
                        dadosPorData[dataItem].infraestrutura++;
                    } else if (linhaCompleta.includes("NIVEL 2") || linhaCompleta.includes("N2")) {
                        dadosPorData[dataItem].resolucaoN2++;
                    } else if (
                        feitoNormalizado.includes("OK") ||
                        feitoNormalizado.includes("ESCALONAMENTO") ||
                        feitoNormalizado.includes("FEITO") ||
                        feitoNormalizado.includes("ENCERRAMENTO")
                    ) {
                        dadosPorData[dataItem].execucao++;
                        dadosPorData[dataItem].produtividade += 1;
                    }
                }

                dadosPorData[dataItem].totalProtocolos =
                    dadosPorData[dataItem].planejamento +
                    dadosPorData[dataItem].execucao +
                    dadosPorData[dataItem].remarcacao +
                    dadosPorData[dataItem].cancelamento +
                    dadosPorData[dataItem].tratativasCS +
                    dadosPorData[dataItem].infraestrutura +
                    dadosPorData[dataItem].resolucaoN2;
            }
        }

        return Object.values(dadosPorData).sort((a, b) => new Date(b.data) - new Date(a.data));
    };

    const verDetalhesTecnico = (tecnico) => {
        const totalProtocolosTecnico =
            tecnico.planejamento +
            tecnico.execucao +
            tecnico.remarcacao +
            tecnico.cancelamento +
            tecnico.tratativasCS +
            tecnico.infraestrutura +
            tecnico.resolucaoN2;

        const temAcionamento = (tecnico.acionamentoExecucao || 0) > 0;
        const temAtivacao = (tecnico.ativacaoExecucao || 0) > 0;
        let tiposEncontrados = "";
        if (temAcionamento && temAtivacao) tiposEncontrados = "AC + AA";
        else if (temAcionamento) tiposEncontrados = "AC (Acionamento)";
        else if (temAtivacao) tiposEncontrados = "AA (Ação de Ativação)";
        else tiposEncontrados = "NORMAL";

        let cargaHoraria = "Não configurado";
        let horarioTrabalho = "Não definido";
        if (tecnico.tipoTecnico === "Comercial") {
            cargaHoraria = "Comercial";
            horarioTrabalho = "08:00 às 17:30 (Seg-Sex) / 08:00 às 12:00 (Sáb)";
        } else if (tecnico.tipoTecnico === "12/36") {
            cargaHoraria = "12x36";
            horarioTrabalho = "09:00 às 21:00";
        }

        const dadosPorData = processarDadosPorData(tecnico.tecnico, tecnico.tipoTecnico);

        let metaTotalProdutividade = 0;
        let metaTotalProtocolos = 0;
        let diasComMeta = 0;

        dadosPorData.forEach(item => {
            const metaDia = calcularMeta(tecnico.tipoTecnico, 0, 0, item.data);
            if (metaDia.produtividadeMin > 0) {
                metaTotalProdutividade += metaDia.produtividadeMin;
                metaTotalProtocolos += metaDia.protocolosMin;
                diasComMeta++;
            }
        });

        const atingiuMetaTotal = tecnico.produtividade >= metaTotalProdutividade;
