            const dataStr = item.linha[0].toString().trim();
            const dataRegex = /^(\d{1,2})\/(\d{1,2})\/(\d{4})$/;
            const match = dataStr.match(dataRegex);
            if (match) {
                return `${match[3]}-${match[2].padStart(2, "0")}-${match[1].padStart(2, "0")}`;
            }
