        let csvContent =
            "Técnico,Regional,Tipo Configurado,Planejamento,Execução,Remarcação,Cancelamento,Tratativas CS,Infraestrutura,Resolução N2,Total Executado,Produtividade,Meta Produtividade,Meta Protocolos,Status,Execução NORMAL,Produtividade NORMAL,Execução ACIONAMENTO,Produtividade ACIONAMENTO,Execução ATIVAÇÃO,Produtividade ATIVAÇÃO\n";

        dadosProdutividade.forEach((item) => {
            csvContent += `"${item.tecnico}",${item.regional},${item.tipoTecnico || "Não configurado"},${
                item.planejamento
            },${item.execucao},${item.remarcacao},${item.cancelamento},${item.tratativasCS},${item.infraestrutura},${
                item.resolucaoN2
            },${item.totalExecutado},${item.produtividade.toFixed(2)},${item.meta.produtividadeMin || "-"},${
