            },${item.meta.status},${item.normalExecucao || 0},${(item.normalProdutividade || 0).toFixed(2)},${
                item.acionamentoExecucao || 0
            },${(item.acionamentoProdutividade || 0).toFixed(2)},${item.ativacaoExecucao || 0},${(
                item.ativacaoProdutividade || 0
            ).toFixed(2)}\n`;
        });

        const blob = new Blob([csvContent], {type: "text/csv;charset=utf-8;"});
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `produtividade_${dataInicio}_a_${dataFim}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        Swal.fire({
            icon: "success",
            title: "Exportado!",
            text: "Arquivo CSV gerado com sucesso",
            toast: true,
            timer: 2000,
        });
