                    <div className="summary-cards-produtividade">
                        <div className="summary-card-prod">
                            <div className="card-icon-prod" style={{background: "#E8465D20"}}>
                                <i className="fas fa-tasks" style={{color: "#E8465D"}}></i>
                            </div>
                            <div className="card-info-prod">
                                <h3>{totalProtocolos}</h3>
                                <p>Total de Protocolos</p>
                            </div>
                        </div>
                        <div className="summary-card-prod">
                            <div className="card-icon-prod" style={{background: "#28a74520"}}>
                                <i className="fas fa-check-circle" style={{color: "#28a745"}}></i>
                            </div>
                            <div className="card-info-prod">
                                <h3>{metricasFiltradas.execucao}</h3>
                                <p>Protocolos Executados</p>
                            </div>
                        </div>
                        <div className="summary-card-prod">
                            <div className="card-icon-prod" style={{background: "#ffc10720"}}>
                                <i className="fas fa-chart-line" style={{color: "#ffc107"}}></i>
                            </div>
                            <div className="card-info-prod">
                                <h3>{metricasFiltradas.totalProdutividade.toFixed(2)}</h3>
                                <p>Produtividade Total</p>
                            </div>
                        </div>
                    </div>

                    <div className="charts-grid-produtividade">
                        <div className="chart-card-prod">
                            <div className="chart-header-prod">
                                <i className="fas fa-chart-bar"></i>
                                <h4>Métricas por Tipo</h4>
                            </div>
                            <canvas ref={metricasChartRef} id="metricasGeraisChart" height="280"></canvas>
                        </div>
                        <div className="chart-card-prod">
                            <div className="chart-header-prod">
                                <i className="fas fa-chart-pie"></i>
                                <h4>Distribuição Percentual</h4>
                            </div>
                            <canvas ref={distribuicaoChartRef} id="distribuicaoChart" height="280"></canvas>
                        </div>
                        <div className="chart-card-prod">
                            <div className="chart-header-prod">
                                <i className="fas fa-chart-bar"></i>
                                <h4>Produtividade por Regional</h4>
                            </div>
                            <canvas ref={regionalChartRef} id="regionalChart" height="280"></canvas>
                        </div>
                        <div className="chart-card-prod chart-full-width">
                            <div className="chart-header-prod">
                                <i className="fas fa-trophy"></i>
                                <h4>Produtividade por Técnico</h4>
                            </div>
                            <canvas ref={tecnicosChartRef} id="produtividadeTecnicosChart" height="300"></canvas>
